70: // Given a listener, dumps the version info, update time and configuration into the
71: // DynamicListenerState provided.
72: void fillState(envoy::admin::v3::ListenersConfigDump::DynamicListenerState& state,
73:                const ListenerImpl& listener) {
74:   state.set_version_info(listener.versionInfo());
